class Car(val make: String, val model: String, var year: Int) {
    val age: Int
        get() = 2026 - year

    fun displayInfo() {
        println("$year $make $model (Age: $age years)")
    }
}

fun main() {
    val car = Car("Toyota", "Camry", 2020)
    car.displayInfo()  // 2020 Toyota Camry (Age: 6 years)
    println("Make: ${car.make}")
}
